HEN 'In Market' WHEN `campaign_name` like '%- SPV%' THEN 'Similar Product View' WHEN `campaign_name` like '%- VA%' THEN 'Similar Product View' WHEN `campaign_name` like '%-PRT%' THEN 'Purchase Retargeting' WHEN `campaign_name` like '%-Retargeting%' THEN 'Non-Purchase Retargeting' WHEN `campaign_name` like '%-Contextual%' THEN 'Category Targeting' WHEN `campaign_name` like '%-IM%' THEN 'In Market' WHEN `campaign_name` like '%In-Market%' THEN 'In Market' WHEN `campaign_name` like '%-SPV%' THEN 'Similar Product View' WHEN `campaign_name` like '%Purchase Retargeting%' THEN 'Purchase Retargeting' WHEN `campaign_name` like '%Non-Purchase%' THEN 'Non-Purchase Retargeting' WHEN `campaign_name` like '%In Market%' THEN 'In Market' WHEN `campaign_name` like '%Category Targeting%' THEN 'Category Targeting' WHEN `campaign_name` like '%Similar Product View%' THEN 'Similar Product View' ELSE  CONCAT('Custom-', SUBSTRING_INDEX(SUBSTRING_INDEX(`campaign_name`, '-', 2), '-', -1)) END when `campaign_name` = 'Nest - STV Retargeting' THEN 'STV Retargeting' when (`advertising_campaigns.type` = 'sp') then 'Sponsored Product' when (`advertising_campaigns.type` = 'sb') then 'Sponsored Brand' when (`advertising_campaigns.type` = 'sd') then 'Sponsored Display' when (`advertising_campaigns.type` = 'sbv') then 'Sponsored Brand Video' when (`advertising_campaigns.type` = '') then 'Unknown' when (`advertising_campaigns.type` = NULL) then 'Unknown' when `advertising_campaigns.name` LIKE '%Lookalike%' then 'Lookalike' when `advertising_campaigns.name` LIKE '%Reward Ads%' then 'Rewards' when `advertising_campaigns.name` LIKE '%Retargeting - Q2%' then 'Spanish Language' when `advertising_campaigns.name` LIKE '%Similar%' then 'Similar Product Views' when `advertising_campaigns.name` LIKE '%market%' then 'In Market' when `advertising_campaigns.name` LIKE '%Market%' then 'In Market' when `advertising_campaigns.name` LIKE '%Contextual%' then 'Category Targeting' when `advertising_campaigns.name` LIKE '%SPV%' then 'Similar Product Views' when `advertising_campaigns.name` LIKE '%CTV%' then 'CTV' when `advertising_campaigns.name` LIKE '%Video%' then 'Video' when `advertising_campaigns.name` LIKE '%Retarget%' and `advertising_campaigns.type` like '%Loyalty' then 'Purchase Retargeting' when `advertising_campaigns.name` LIKE '%Retarget%' then 'Non Purchase Retargeting' when `advertising_campaigns.name` LIKE '%Mid Funnel%' then 'Non Purchase Retargeting' when `advertising_campaigns.name` LIKE '%Lower Funnel%' then 'Non Purchase Retargeting' else `advertising_campaigns.type` end) AS `ADType` FROM _Join_Data_5
